<template>
  <div class="about-container">
    <el-card>
      <div slot="header" class="clearfix">
        <span>关于系统</span>
      </div>
      
      <div class="about-content">
        <div class="system-logo">
          <img src="@/assets/images/logo.png" alt="系统Logo" class="logo-image">
          <h2 class="system-name">茶叶小程序管理系统</h2>
          <div class="system-version">Version 1.0.0</div>
        </div>
        
        <el-divider></el-divider>
        
        <div class="info-section">
          <h3 class="section-title">系统信息</h3>
          <el-row :gutter="20" class="info-list">
            <el-col :span="8">
              <div class="info-item">
                <div class="info-label">系统版本</div>
                <div class="info-value">v1.0.0</div>
              </div>
            </el-col>
            <el-col :span="8">
              <div class="info-item">
                <div class="info-label">发布日期</div>
                <div class="info-value">2024-03-28</div>
              </div>
            </el-col>
            <el-col :span="8">
              <div class="info-item">
                <div class="info-label">框架版本</div>
                <div class="info-value">Vue 2.6.12 / Element UI 2.15.7</div>
              </div>
            </el-col>
            <el-col :span="8">
              <div class="info-item">
                <div class="info-label">服务器环境</div>
                <div class="info-value">Node.js 16.x / MongoDB 5.0</div>
              </div>
            </el-col>
            <el-col :span="8">
              <div class="info-item">
                <div class="info-label">客户端</div>
                <div class="info-value">{{clientInfo.browser}} {{clientInfo.version}}</div>
              </div>
            </el-col>
            <el-col :span="8">
              <div class="info-item">
                <div class="info-label">操作系统</div>
                <div class="info-value">{{clientInfo.os}}</div>
              </div>
            </el-col>
          </el-row>
        </div>
        
        <div class="info-section">
          <h3 class="section-title">版本信息</h3>
          <el-timeline>
            <el-timeline-item
              v-for="(version, index) in versionHistory"
              :key="index"
              :timestamp="version.date"
              :type="index === 0 ? 'primary' : ''"
              :icon="index === 0 ? 'el-icon-star-on' : ''"
              placement="top"
            >
              <h4>{{version.version}}</h4>
              <ul class="version-features">
                <li v-for="(feature, idx) in version.features" :key="idx">{{feature}}</li>
              </ul>
            </el-timeline-item>
          </el-timeline>
        </div>
        
        <div class="info-section">
          <h3 class="section-title">技术栈</h3>
          <div class="tech-stack">
            <el-tag
              v-for="(tech, index) in techStack"
              :key="index"
              :type="tech.type"
              effect="plain"
              class="tech-tag"
            >
              {{tech.name}}
            </el-tag>
          </div>
        </div>
        
        <div class="info-section">
          <h3 class="section-title">联系我们</h3>
          <p class="contact-info">
            <i class="el-icon-phone"></i> 电话：请在系统配置中设置
          </p>
          <p class="contact-info">
            <i class="el-icon-message"></i> 邮箱：请在系统配置中设置
          </p>
          <p class="contact-info">
            <i class="el-icon-location-information"></i> 地址：请在系统配置中设置
          </p>
        </div>
        
        <div class="copyright">
          © 2026 茶叶小程序管理系统 All Rights Reserved.
        </div>
      </div>
    </el-card>
  </div>
</template>

<script>
export default {
  name: 'About',
  data() {
    return {
      clientInfo: {
        browser: 'Unknown',
        version: '',
        os: 'Unknown'
      },
      versionHistory: [
        {
          version: 'v1.0.0',
          date: '2024-03-28',
          features: [
            '完成基础管理后台框架搭建',
            '实现用户管理功能',
            '实现商品管理功能',
            '实现订单管理功能',
            '实现分类管理功能',
            '实现统计分析功能',
            '实现系统设置功能'
          ]
        },
        {
          version: 'v0.9.0',
          date: '2024-03-20',
          features: [
            '完成后台基础框架开发',
            '实现登录认证功能',
            '完成基础API接口设计',
            '完成数据库设计'
          ]
        },
        {
          version: 'v0.5.0',
          date: '2024-03-10',
          features: [
            '项目初始化',
            '需求分析与设计',
            '技术选型与架构设计'
          ]
        }
      ],
      techStack: [
        { name: 'Vue.js', type: '' },
        { name: 'Element UI', type: 'success' },
        { name: 'Vuex', type: 'info' },
        { name: 'Vue Router', type: 'warning' },
        { name: 'Axios', type: 'danger' },
        { name: 'Node.js', type: '' },
        { name: 'Express', type: 'success' },
        { name: 'MongoDB', type: 'info' },
        { name: 'JWT', type: 'warning' },
        { name: 'Webpack', type: 'danger' },
        { name: 'SCSS', type: '' },
        { name: 'ESLint', type: 'success' }
      ]
    }
  },
  mounted() {
    this.detectClientInfo()
  },
  methods: {
    // 获取客户端信息
    detectClientInfo() {
      const userAgent = navigator.userAgent
      
      // 检测浏览器
      if (userAgent.indexOf('Chrome') > -1) {
        this.clientInfo.browser = 'Chrome'
      } else if (userAgent.indexOf('Firefox') > -1) {
        this.clientInfo.browser = 'Firefox'
      } else if (userAgent.indexOf('Safari') > -1) {
        this.clientInfo.browser = 'Safari'
      } else if (userAgent.indexOf('Edge') > -1 || userAgent.indexOf('Edg') > -1) {
        this.clientInfo.browser = 'Edge'
      } else if (userAgent.indexOf('MSIE') > -1 || userAgent.indexOf('Trident') > -1) {
        this.clientInfo.browser = 'Internet Explorer'
      }
      
      // 提取版本号（简单实现，实际可能需要更复杂的正则表达式）
      const versionMatch = userAgent.match(new RegExp(this.clientInfo.browser + '\\/(\\d+\\.\\d+)'))
      if (versionMatch && versionMatch.length > 1) {
        this.clientInfo.version = versionMatch[1]
      }
      
      // 检测操作系统
      if (userAgent.indexOf('Windows') > -1) {
        this.clientInfo.os = 'Windows'
      } else if (userAgent.indexOf('Mac') > -1) {
        this.clientInfo.os = 'macOS'
      } else if (userAgent.indexOf('Linux') > -1) {
        this.clientInfo.os = 'Linux'
      } else if (userAgent.indexOf('Android') > -1) {
        this.clientInfo.os = 'Android'
      } else if (userAgent.indexOf('iPhone') > -1 || userAgent.indexOf('iPad') > -1) {
        this.clientInfo.os = 'iOS'
      }
    }
  }
}
</script>

