  padding: 20px;
  
  .about-content {
    padding: 20px 0;
  }
  
  .system-logo {
    text-align: center;
    margin-bottom: 30px;
    
    .logo-image {
      width: 120px;
      height: 120px;
      margin-bottom: 15px;
    }
    
    .system-name {
      font-size: 24px;
      font-weight: bold;
      color: #303133;
      margin-bottom: 5px;
    }
    
    .system-version {
      font-size: 14px;
      color: #909399;
    }
  }
  
  .info-section {
    margin-bottom: 30px;
    
    .section-title {
      font-size: 18px;
      font-weight: bold;
